patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 0632f3cfc6dd..7b70f349bee7 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2617,6 +2617,31 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         return replaceOperand(*II, 0, InnerSrc);
       }
     }
+    // ldexp(x, zext(i1 y)) -> x * (y ? 2.0 : 1.0)
+    // ldexp(x, sext(i1 y)) -> x * (y ? 0.5 : 1.0)
+    Value *Cond;
+    if (match(Exp, m_ZExt(m_Value(Cond))) && Cond->getType()->isIntegerTy(1)) {
+      Value *Factor = Builder.CreateSelect(Cond,
+          ConstantFP::get(Src->getType(), 2.0),
+          ConstantFP::get(Src->getType(), 1.0));
+      Factor->setName("select");
+      Value *Mul = Builder.CreateFMul(Factor, Src);
+      Mul->setName("mul");
+      if (auto *MulI = dyn_cast<Instruction>(Mul))
+        MulI->copyFastMathFlags(II);
+      return replaceInstUsesWith(*II, Mul);
+    }
+    if (match(Exp, m_SExt(m_Value(Cond))) && Cond->getType()->isIntegerTy(1)) {
+      Value *Factor = Builder.CreateSelect(Cond,
+          ConstantFP::get(Src->getType(), 0.5),
+          ConstantFP::get(Src->getType(), 1.0));
+      Factor->setName("select");
+      Value *Mul = Builder.CreateFMul(Src, Factor);
+      Mul->setName("mul");
+      if (auto *MulI = dyn_cast<Instruction>(Mul))
+        MulI->copyFastMathFlags(II);
+      return replaceInstUsesWith(*II, Mul);
+    }

     break;
   }

